"""
Tests for WCAG 2.1 AA keyboard navigation requirements.

Success Criteria covered:
  - 2.1.1  Keyboard (Level A)
  - 2.1.2  No Keyboard Trap (Level A)
  - 2.4.3  Focus Order (Level A)
  - 2.4.7  Focus Visible (Level AA)
  - 2.4.11 Focus Appearance (Level AA, WCAG 2.2)
"""

import pytest
from playwright.sync_api import Page, expect
from helpers.keyboard_utils import Key, FOCUSABLE_ELEMENTS, INTERACTIVE_ROLES


# ── helpers ───────────────────────────────────────────────────────────────────

def get_focusable_elements(page: Page) -> list:
    selector = ", ".join(FOCUSABLE_ELEMENTS)
    return page.query_selector_all(selector)


def get_focused_element_info(page: Page) -> dict:
    return page.evaluate("""() => {
        const el = document.activeElement;
        if (!el) return null;
        const style = window.getComputedStyle(el);
        const rect  = el.getBoundingClientRect();
        return {
            tagName:    el.tagName.toLowerCase(),
            type:       el.type       || null,
            role:       el.getAttribute('role') || el.tagName.toLowerCase(),
            tabIndex:   el.tabIndex,
            ariaLabel:  el.getAttribute('aria-label') || null,
            id:         el.id         || null,
            outlineStyle:  style.outlineStyle,
            outlineWidth:  style.outlineWidth,
            outlineColor:  style.outlineColor,
            outlineOffset: style.outlineOffset,
            boxShadow:     style.boxShadow,
            visible: rect.width > 0 && rect.height > 0,
        };
    }""")


def element_has_visible_focus_indicator(element_info: dict) -> bool:
    """
    Return True when a focus indicator is visible.
    Accepts outline OR a distinguishable box-shadow.
    """
    if not element_info:
        return False

    has_outline = (
        element_info["outlineStyle"] not in ("none", "")
        and element_info["outlineWidth"] not in ("0px", "")
    )
    has_shadow = (
        element_info["boxShadow"] not in ("none", "")
    )
    return has_outline or has_shadow


# ── TC-KN-001 : every screen has at least one focusable element ───────────────

@pytest.mark.keyboard
@pytest.mark.wcag
class TestFocusableElementsExist:

    def test_screen_has_focusable_elements(self, screen):
        """Every UI screen must expose at least one focusable element."""
        page = screen["page"]
        elements = get_focusable_elements(page)
        assert len(elements) > 0, (
            f"[{screen['name']}] No focusable elements found. "
            "All interactive content must be keyboard-reachable (WCAG 2.1.1)."
        )

    def test_body_element_is_not_only_focusable(self, screen):
        """Screens must not rely solely on the body as a focus target."""
        page = screen["page"]
        elements = get_focusable_elements(page)
        non_body = [
            el for el in elements
            if el.evaluate("e => e.tagName.toLowerCase()") != "body"
        ]
        assert len(non_body) > 0, (
            f"[{screen['name']}] Only <body> is focusable — "
            "meaningful interactive elements must be reachable via keyboard."
        )


# ── TC-KN-002 : Tab key cycles through all interactive elements ───────────────

@pytest.mark.keyboard
@pytest.mark.wcag
class TestTabNavigation:

    def test_tab_reaches_all_interactive_elements(self, screen):
        """
        Pressing Tab should move focus through every interactive element.
        WCAG SC 2.1.1 / 2.4.3
        """
        page = screen["page"]
        page.keyboard.press(Key.TAB)

        focusable = get_focusable_elements(page)
        max_tabs = len(focusable) + 5   # small buffer for hidden / dynamic items
        visited_ids: list[dict] = []

        for _ in range(max_tabs):
            info = get_focused_element_info(page)
            if info:
                visited_ids.append(info)
            page.keyboard.press(Key.TAB)

        assert len(visited_ids) >= len(focusable), (
            f"[{screen['name']}] Tab navigation visited {len(visited_ids)} elements, "
            f"expected at least {len(focusable)}."
        )

    def test_shift_tab_reverses_focus_order(self, screen):
        """
        Shift+Tab must move focus in reverse order (WCAG SC 2.4.3).
        """
        page = screen["page"]

        # move forward two stops
        page.keyboard.press(Key.TAB)
        page.keyboard.press(Key.TAB)
        second_element = get_focused_element_info(page)

        # move back one stop
        page.keyboard.press(Key.SHIFT_TAB)
        first_element = get_focused_element_info(page)

        assert second_element != first_element, (
            f"[{screen['name']}] Shift+Tab did not move focus to a different element."
        )

    def test_tab_order_is_logical(self, screen):
        """
        Focus order must follow the visual / DOM reading order (WCAG SC 2.4.3).
        Verifies that tabIndex values don't create an illogical sequence.
        """
        page = screen["page"]
        tab_indices: list[int] = page.evaluate("""() => {
            const selector = %s;
            return Array.from(document.querySelectorAll(selector))
                .map(el => el.tabIndex)
                .filter(i => i >= 0);
        }""" % repr(", ".join(FOCUSABLE_ELEMENTS)))

        positive_indices = [i for i in tab_indices if i > 0]
        # Positive tabIndex values create non-DOM order — flag as a warning.
        assert len(positive_indices) == 0, (
            f"[{screen['name']}] Found {len(positive_indices)} elements with positive "
            "tabIndex values which can disrupt logical focus order (WCAG 2.4.3). "
            f"Values: {sorted(set(positive_indices))}"
        )


# ── TC-KN-003 : no keyboard trap ─────────────────────────────────────────────

@pytest.mark.keyboard
@pytest.mark.wcag
class TestNoKeyboardTrap:

    def test_no_keyboard_trap_on_screen(self, screen):
        """
        Focus must not become trapped on any single element (WCAG SC 2.1.2).
        Tests that Tab advances focus beyond any given element within 3 presses.
        """
        page = screen["page"]
        max_presses = 3

        for _ in range(10):   # spot-check 10 consecutive focus stops
            before = get_focused_element_info(page)
            trapped = True

            for _ in range(max_presses):
                page.keyboard.press(Key.TAB)
                after = get_focused_element_info(page)
                if after != before:
                    trapped = False
                    break

            assert not trapped, (
                f"[{screen['name']}] Keyboard trap detected on element: {before}. "
                "Tab key must be able to leave every focusable element (WCAG 2.1.2)."
            )

    def test_modal_dialog_trap_is_intentional_and_escapable(self, page):
        """
        When a modal is open, focus must be contained within it AND
        Escape must close it (WCAG SC 2.1.2 — intentional trap).
        """
        page.goto(f"http://localhost:3000/dashboard")
        page.wait_for_load_state("networkidle")

        # Open a modal if a trigger exists
        modal_trigger = page.query_selector("[data-testid='modal-trigger']")
        if not modal_trigger:
            pytest.skip("No modal trigger found on dashboard — skipping modal trap test.")

        modal_trigger.click()
        page.wait_for_selector("[role='dialog']", state="visible")

        # Tab through dialog — focus should stay within it
        for _ in range(10):
            page.keyboard.press(Key.TAB)
            focused_info = get_focused_element_info(page)
            is_inside_modal = page.evaluate("""() => {
                const dialog = document.querySelector("[role='dialog']");
                return dialog && dialog.contains(document.activeElement);
            }""")
            assert is_inside_modal, (
                f"Focus escaped modal dialog to: {focused_info}. "
                "Focus must remain within an open dialog (WCAG 2.1.2)."
            )

        # Escape must close the modal
        page.keyboard.press(Key.ESCAPE)
        modal_visible = page.is_visible("[role='dialog']")
        assert not modal_visible, (
            "Pressing Escape did not close the modal dialog (WCAG 2.1.2 / best practice)."
        )


# ── TC-KN-004 : focus indicator is visible ───────────────────────────────────

@pytest.mark.keyboard
@pytest.mark.wcag
class TestFocusVisible:

    def test_focused_elements_have_visible_indicator(self, screen):
        """
        Every focusable element must have a visible focus indicator (WCAG SC 2.4.7).
        """
        page = screen["page"]
        failures: list[str] = []

        focusable = get_focusable_elements(page)
        for i, _ in enumerate(focusable):
            page.keyboard.press(Key.TAB)
            info = get_focused_element_info(page)

            if info and not element_has_visible_focus_indicator(info):
                failures.append(
                    f"Element #{i + 1} — tag=<{info['tagName']}> "
                    f"id={info['id']!r} role={info['role']!r}: "
                    f"outline='{info['outlineStyle']} {info['outlineWidth']}', "
                    f"boxShadow='{info['boxShadow']}'"
                )

        assert not failures, (
            f"[{screen['name']}] {len(failures)} element(s) lack a visible focus "
            f"indicator (WCAG SC 2.4.7):\n" + "\n".join(failures)
        )

    def test_focus_indicator_not_hidden_by_overflow(self, screen):
        """
        The focus ring must not be clipped by overflow:hidden on a parent (WCAG 2.4.7).
        """
        page = screen["page"]
        clipped: list[str] = []

        focusable = get_focusable_elements(page)
        for _ in focusable:
            page.keyboard.press(Key.TAB)
            is_clipped = page.evaluate("""() => {
                const el = document.activeElement;
                if (!el) return false;
                let parent = el.parentElement;
                while (parent && parent !== document.body) {
                    const style = window.getComputedStyle(parent);
                    if (style.overflow === 'hidden' || style.overflowX === 'hidden') {
                        const elRect     = el.getBoundingClientRect();
                        const parentRect = parent.getBoundingClientRect();
                        if (
                            elRect.left   < parentRect.left  ||
                            elRect.right  > parentRect.right ||
                            elRect.top    < parentRect.top   ||
                            elRect.bottom > parentRect.bottom
                        ) return true;
                    }
                    parent = parent.parentElement;
                }
                return false;
            }""")

            if is_clipped:
                info = get_focused_element_info(page)
                clipped.append(f"<{info['tagName']}> id={info['id']!r}")

        assert not clipped, (
            f"[{screen['name']}] Focus ring clipped by overflow:hidden on: "
            + ", ".join(clipped)
        )


# ── TC-KN-005 : widget-specific keyboard patterns ────────────────────────────

@pytest.mark.keyboard
@pytest.mark.wcag
class TestWidgetKeyboardPatterns:
    """
    Validates ARIA Authoring Practices Guide (APG) keyboard patterns
    for common widget types.
    """

    def test_button_activates_on_enter_and_space(self, page):
        """Buttons must respond to both Enter and Space (ARIA APG)."""
        page.goto("http://localhost:3000/dashboard")
        page.wait_for_load_state("networkidle")

        buttons = page.query_selector_all("button:not([disabled])")
        if not buttons:
            pytest.skip("No buttons found on dashboard.")

        activated_enter = page.evaluate("""() => {
            const btn = document.querySelector('button:not([disabled])');
            if (!btn) return false;
            btn.focus();
            let clicked = false;
            btn.addEventListener('click', () => { clicked = true; }, { once: true });
            btn.dispatchEvent(new KeyboardEvent('keydown', { key: 'Enter', bubbles: true }));
            btn.dispatchEvent(new KeyboardEvent('keyup',  { key: 'Enter', bubbles: true }));
            return clicked;
        }""")
        assert activated_enter, "Button did not activate on Enter key."

        activated_space = page.evaluate("""() => {
            const btn = document.querySelector('button:not([disabled])');
            if (!btn) return false;
            btn.focus();
            let clicked = false;
            btn.addEventListener('click', () => { clicked = true; }, { once: true });
            btn.dispatchEvent(new KeyboardEvent('keydown', { key: ' ', bubbles: true }));
            btn.dispatchEvent(new KeyboardEvent('keyup',   { key: ' ', bubbles: true }));
            return clicked;
        }""")
        assert activated_space, "Button did not activate on Space key."

    def test_checkbox_toggles_on_space(self, page):
        """Checkboxes must toggle with Space key (ARIA APG)."""
        page.goto("http://localhost:3000/settings")
        page.wait_for_load_state("networkidle")

        checkbox = page.query_selector("input[type='checkbox']:not([disabled])")
        if not checkbox:
            pytest.skip("No checkbox found on settings screen.")

        checkbox.focus()
        initial_state = checkbox.is_checked()
        page.keyboard.press(Key.SPACE)
        assert checkbox.is_checked() != initial_state, (
            "Checkbox did not toggle when Space key was pressed."
        )

    def test_dropdown_menu_opens_with_enter_or_space(self, page):
        """Dropdown / combobox menus must open on Enter or Space (ARIA APG)."""
        page.goto("http://localhost:3000/dashboard")
        page.wait_for_load_state("networkidle")

        dropdown = page.query_selector("[role='combobox'], select")
        if not dropdown:
            pytest.skip("No dropdown found on dashboard.")

        dropdown.focus()
        page.keyboard.press(Key.ENTER)
        expanded = page.evaluate("""() => {
            const el = document.activeElement;
            return el && el.getAttribute('aria-expanded') === 'true';
        }""")
        assert expanded, (
            "Dropdown did not expand on Enter key (WCAG 2.1.1 / ARIA APG)."
        )

    def test_radio_group_navigable_with_arrow_keys(self, page):
        """Radio button groups must use arrow keys for internal navigation (ARIA APG)."""
        page.goto("http://localhost:3000/settings")
        page.wait_for_load_state("networkidle")

        radios = page.query_selector_all("input[type='radio']:not([disabled])")
        if len(radios) < 2:
            pytest.skip("Fewer than 2 radio buttons found — skipping group navigation test.")

        radios[0].focus()
        page.keyboard.press(Key.ARROW_DOWN)
        focused_info = get_focused_element_info(page)
        assert focused_info["type"] == "radio", (
            "Arrow Down did not move focus within radio group."
        )

    def test_links_activate_on_enter(self, page):
        """Anchor links must be activated by Enter key (WCAG 2.1.1)."""
        page.goto("http://localhost:3000/")
        page.wait_for_load_state("networkidle")

        link = page.query_selector("a[href]:not([href='#'])")
        if not link:
            pytest.skip("No navigable link found on home screen.")

        href = link.get_attribute("href")
        link.focus()
        with page.expect_navigation():
            page.keyboard.press(Key.ENTER)

        assert page.url != "http://localhost:3000/", (
            f"Enter key did not navigate the link pointing to {href}."
        )

    def test_tabs_widget_navigable_with_arrow_keys(self, page):
        """Tab widgets must use arrow keys between tabs (ARIA APG — tab pattern)."""
        page.goto("http://localhost:3000/dashboard")
        page.wait_for_load_state("networkidle")

        tab_list = page.query_selector("[role='tablist']")
        if not tab_list:
            pytest.skip("No tablist found on dashboard.")

        first_tab = page.query_selector("[role='tab']")
        first_tab.focus()
        page.keyboard.press(Key.ARROW_RIGHT)

        focused_role = page.evaluate(
            "() => document.activeElement.getAttribute('role')"
        )
        assert focused_role == "tab", (
            "Arrow Right did not move focus to the next tab (ARIA APG tab pattern)."
        )
