## `test_contrast_ratios.py`

```python
"""
Tests for WCAG 2.1 AA contrast ratio requirements.

Success Criteria covered:
  - 1.4.3  Contrast (Minimum) — Level AA  — 4.5:1 normal, 3:1 large text
  - 1.4.11 Non-text Contrast  — Level AA  — 3:1 for UI components & graphics
"""

import pytest
from playwright.sync_api import Page
from helpers.color_utils import (
    contrast_ratio_from_hex,
    hex_to_rgb,
    calculate_contrast_ratio,
    WCAG_AA_NORMAL_TEXT_RATIO,
    WCAG_AA_LARGE_TEXT_RATIO,
    WCAG_AA_UI_COMPONENT_RATIO,
)


# ── helpers ───────────────────────────────────────────────────────────────────

def parse_rgb_string(rgb_str: str) -> tuple[int, int, int]:
    """Parse 'rgb(r, g, b)' or 'rgba(r, g, b, a)' to an (r, g, b) tuple."""
    rgb_str = rgb_str.strip()
    inner = rgb_str[rgb_str.index("(") + 1: rgb_str.index(")")]
    parts = [p.strip() for p in inner.split(",")]
    return int(float(parts[0])), int(float(parts[1])), int(float(parts[2]))


def get_text_elements_with_colors(page: Page) -> list[dict]:
    """
    Extract text elements with their computed foreground / background colors
    and font size from the rendered page.
    """
    return page.evaluate("""() => {
        const results = [];
        const walker  = document.createTreeWalker(
            document.body,
            NodeFilter.SHOW_TEXT,
            null
        );

        let node;
        while ((node = walker.nextNode())) {
            const text   = node.nodeValue.trim();
            const parent = node.parentElement;
            if (!text || !parent) continue;

            const rect  = parent.getBoundingClientRect();
            if (rect.width === 0 || rect.height === 0) continue;   // invisible

            const style = window.getComputedStyle(parent);
            if (style.visibility === 'hidden' || style.display === 'none') continue;

            results.push({
                text:        text.substring(0, 60),
                tag:         parent.tagName.toLowerCase(),
                color:       style.color,
                background:  style.backgroundColor,
                fontSize:    parseFloat(style.fontSize),
                fontWeight:  style.fontWeight,
            });
        }
        return results;
    }""")


def get_ui_component_colors(page: Page) -> list[dict]:
    """Extract interactive UI component colors for non-text contrast testing."""
    return page.evaluate("""() => {
        const selectors = [
            'button:not([disabled])',
            'input[type="text"]',
            'input[type="email"]',
            'input[type="password"]',
            'input[type="search"]',
            'select',
            'textarea',
            '[role="checkbox"]',
            '[role="radio"]',
            '[role="switch"]',
            '[role="slider"]',
            'input[type="checkbox"]',
            'input[type="radio"]',
        ];
        const results = [];

        selectors.forEach(sel => {
            document.querySelectorAll(sel).forEach(el => {
                const rect  = el.getBoundingClientRect();
